// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;




contract chai{
    address public owner;
    uint  price;
     mapping(address=>user) public customer;



    struct user{
    string name;
    string message;
    uint timestamp;
    address from;
    }

    user[] public memo;


    constructor()
    {
        owner=msg.sender;
    } 
    modifier onlyOwner() {
        require(msg.sender==owner,"only owner can call this function!");
        _;
    }



    function setPrice(uint _price) public onlyOwner(){
        price=_price;
    }
    function showPrice() public view returns(uint)
    {
        return price;
    }

    function buy(string memory _name,string memory _msg) public  payable{
        require(msg.value==price,"pay!");
        memo.push(user(_name,_msg,block.timestamp,msg.sender));
    }
    function getMemo() public view returns(user[] memory)
    {
        return memo;
    }




}
